{"examples":[{"code":"def sum_values(nums: list[int]) -> int {
    total = 0;
    for n in nums {
        total = total + n;
    }
    return total;
}

with entry {
    values = [4, 7, 1, 8];
    print(sum_values(values));
}","complexity":"simple","prompt":"Write a small Jac program with a typed function that sums a list of integers and prints the result for a sample list."},{"code":"def shipping_label(weight: int) -> str {
    if weight <= 0 {
        return "invalid";
    }
    if weight <= 2 {
        return "letter";
    }
    if weight <= 10 {
        return "parcel";
    }
    return "freight";
}

with entry {
    print(shipping_label(7));
    print(shipping_label(15));
}","complexity":"simple","prompt":"Create a Jac utility function that classifies a package weight as invalid, letter, parcel, or freight, then print two sample classifications."},{"code":"node Counter {
    has value: int = 0;

    def add(step: int) -> int {
        self.value = self.value + step;
        return self.value;
    }
}

with entry {
    c = Counter(value=10);
    print(c.add(5));
    print(c.add(2));
}","complexity":"simple","prompt":"Define a Counter node with an integer field and an ability that adds a step to it, then demonstrate two increments."},{"code":"def status_text(code: int) -> str {
    if code == 200 {
        return "ok";
    }
    if code == 404 {
        return "not found";
    }
    if code == 500 {
        return "server error";
    }
    return "unknown";
}

with entry {
    print(status_text(200));
    print(status_text(404));
}","complexity":"simple","prompt":"Write a Jac function for a tiny web-style status lookup that maps common HTTP status codes to text and prints two examples."},{"code":"node City {
    has name: str;
    has population: int;
}

with entry {
    a = City(name="Aster", population=1200);
    b = City(name="Brook", population=900);
    root() ++> a;
    a ++> b;
    print(a.name);
    print(b.population);
}","complexity":"simple","prompt":"Create two City nodes, connect them in a simple graph from the root through the first city to the second, and print selected fields."},{"code":"def is_safe_name(name: str) -> bool {
    if name == "" {
        return false;
    }
    if name == "admin" {
        return false;
    }
    return true;
}

with entry {
    print(is_safe_name("guest"));
    print(is_safe_name("admin"));
}","complexity":"simple","prompt":"Implement a simple Jac validation function that rejects an empty name and the reserved name admin."},{"code":"def average_score(scores: list[int]) -> int {
    total = 0;
    count = 0;
    for score in scores {
        total = total + score;
        count = count + 1;
    }
    if count == 0 {
        return 0;
    }
    return total / count;
}

with entry {
    print(average_score([80, 90, 70]));
}","complexity":"simple","prompt":"Write a Jac function that computes the integer average of a list of scores, returning zero for an empty list."},{"code":"def count_even(nums: list[int]) -> int {
    total = 0;
    for n in nums {
        if n % 2 == 0 {
            total = total + 1;
        }
    }
    return total;
}

with entry {
    print(count_even([1, 2, 4, 7, 10]));
}","complexity":"simple","prompt":"Create a Jac program that counts how many numbers in a list are even and prints the count for sample data."},{"code":"node Reading {
    has sensor: str;
    has value: int;
}

walker ReadingTotal {
    has total: int = 0;

    can collect with `root entry {
        visit [-->];
    }

    can collect with Reading entry {
        self.total = self.total + here.value;
    }
}

with entry {
    root() ++> Reading(sensor="a", value=5);
    root() ++> Reading(sensor="b", value=8);
    report = ReadingTotal() spawn root();
    print(report.total);
}","complexity":"medium","prompt":"Build a graph of sensor Reading nodes connected from root and use a walker to total their values."},{"code":"node Product {
    has name: str;
    has price: int;
    has quantity: int;

    def value() -> int {
        return self.price * self.quantity;
    }
}

def inventory_value(items: list[Product]) -> int {
    total = 0;
    for item in items {
        total = total + item.value();
    }
    return total;
}

with entry {
    items = [Product(name="pen", price=2, quantity=10), Product(name="book", price=7, quantity=3)];
    print(inventory_value(items));
}","complexity":"medium","prompt":"Model inventory items as Product nodes with a value ability, then compute the total inventory value for a list of products."},{"code":"node Endpoint {
    has path: str;
    has method: str;
    has handler: str;
}

def route_name(routes: list[Endpoint], path: str, method: str) -> str {
    for route in routes {
        if route.path == path and route.method == method {
            return route.handler;
        }
    }
    return "not_found";
}

with entry {
    routes = [Endpoint(path="/", method="GET", handler="home"), Endpoint(path="/login", method="POST", handler="login")];
    print(route_name(routes, "/login", "POST"));
}","complexity":"medium","prompt":"Create a small web routing table using Endpoint nodes and a function that returns the handler for a matching path and method."},{"code":"def clamp_readings(values: list[int], low: int, high: int) -> list[int] {
    result: list[int] = [];
    for value in values {
        if value < low {
            result.append(low);
        } elif value > high {
            result.append(high);
        } else {
            result.append(value);
        }
    }
    return result;
}

with entry {
    print(clamp_readings([3, 10, 25, 7], 5, 20));
}","complexity":"medium","prompt":"Write a typed Jac data-processing function that clamps a list of readings to a minimum and maximum value."},{"code":"node Page {
    has title: str;
    has views: int;
}

walker PopularPages {
    has threshold: int;
    has count: int = 0;

    can scan with `root entry {
        visit [-->];
    }

    can scan with Page entry {
        if here.views >= self.threshold {
            self.count = self.count + 1;
        }
    }
}

with entry {
    root() ++> Page(title="home", views=50);
    root() ++> Page(title="docs", views=140);
    root() ++> Page(title="blog", views=90);
    w = PopularPages(threshold=100) spawn root();
    print(w.count);
}","complexity":"medium","prompt":"Represent website pages as graph nodes and use a walker to count how many pages meet a view threshold."},{"code":"def retry_delays(start: int, attempts: int) -> list[int] {
    delays: list[int] = [];
    current = start;
    i = 0;
    while i < attempts {
        delays.append(current);
        current = current * 2;
        i = i + 1;
    }
    return delays;
}

with entry {
    print(retry_delays(2, 4));
}","complexity":"medium","prompt":"Implement a Jac utility that returns exponential retry delays using a while loop."},{"code":"node UserSession {
    has user: str;
    has token: str;
    has active: bool;

    def is_valid() -> bool {
        if not self.active {
            return false;
        }
        if self.token == "" {
            return false;
        }
        return true;
    }
}

with entry {
    good = UserSession(user="ada", token="t1", active=true);
    bad = UserSession(user="lin", token="", active=true);
    print(good.is_valid());
    print(bad.is_valid());
}","complexity":"medium","prompt":"Define a UserSession node for a web application and add an ability that validates active sessions with non-empty tokens."},{"code":"def bucket_counts(values: list[int]) -> list[int] {
    small = 0;
    medium = 0;
    large = 0;
    for value in values {
        if value < 10 {
            small = small + 1;
        } elif value < 100 {
            medium = medium + 1;
        } else {
            large = large + 1;
        }
    }
    return [small, medium, large];
}

with entry {
    print(bucket_counts([2, 9, 10, 50, 130]));
}","complexity":"medium","prompt":"Write a data processing function that counts values in small, medium, and large numeric buckets."},{"code":"node Task {
    has title: str;
    has done: bool = false;
    has points: int = 0;

    def finish(points_awarded: int) -> int {
        self.done = true;
        self.points = points_awarded;
        return self.points;
    }
}

walker CompletedPoints {
    has total: int = 0;

    can scan with `root entry {
        visit [-->];
    }

    can scan with Task entry {
        if here.done {
            self.total = self.total + here.points;
        }
    }
}

with entry {
    t1 = Task(title="design");
    t2 = Task(title="build");
    t1.finish(5);
    root() ++> t1;
    root() ++> t2;
    w = CompletedPoints() spawn root();
    print(w.total);
}","complexity":"hard","prompt":"Create task nodes with a finish ability, connect them from root, and use a walker to total the points from completed tasks only."},{"code":"node Service {
    has name: str;
    has healthy: bool;
    has latency: int;

    def status() -> str {
        if not self.healthy {
            return "down";
        }
        if self.latency > 200 {
            return "slow";
        }
        return "ok";
    }
}

def count_status(services: list[Service], wanted: str) -> int {
    count = 0;
    for service in services {
        if service.status() == wanted {
            count = count + 1;
        }
    }
    return count;
}

with entry {
    services = [Service(name="api", healthy=true, latency=90), Service(name="db", healthy=true, latency=250), Service(name="cache", healthy=false, latency=0)];
    print(count_status(services, "ok"));
    print(count_status(services, "slow"));
}","complexity":"hard","prompt":"Model service health checks with nodes and abilities, then count how many services have a requested status."},{"code":"node Cost {
    has label: str;
    has amount: int;
}

node Project {
    has name: str;
    has budget: int;

    def remaining(spent: int) -> int {
        return self.budget - spent;
    }
}

walker CostTotal {
    has total: int = 0;

    can scan with Project entry {
        visit [-->];
    }

    can scan with Cost entry {
        self.total = self.total + here.amount;
    }
}

with entry {
    project = Project(name="launch", budget=1000);
    project ++> Cost(label="design", amount=150);
    project ++> Cost(label="hosting", amount=80);
    root() ++> project;
    w = CostTotal() spawn project;
    print(project.remaining(w.total));
}","complexity":"hard","prompt":"Build a project budget graph where a Project connects to Cost nodes, then use a walker to compute spending and print the remaining budget."},{"code":"node RequestLog {
    has path: str;
    has status: int;
    has millis: int;

    def is_error() -> bool {
        return self.status >= 500;
    }
}

def slow_errors(logs: list[RequestLog], limit: int) -> int {
    count = 0;
    for log in logs {
        if log.is_error() and log.millis > limit {
            count = count + 1;
        }
    }
    return count;
}

with entry {
    logs = [RequestLog(path="/", status=200, millis=30), RequestLog(path="/api", status=500, millis=300), RequestLog(path="/pay", status=502, millis=90)];
    print(slow_errors(logs, 100));
}","complexity":"hard","prompt":"Represent web request logs as nodes and write a function that counts server-error requests slower than a given limit."}]}
